contracts/ResearchRewards.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/Ownable2Step.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

/**
 * @title ResearchRewards
 * @author AI Sanctuary
 * @notice Manages research submissions and token rewards
 * @dev Researchers submit findings, get verified, earn SANC tokens
 */
contract ResearchRewards is Ownable2Step, ReentrancyGuard {
    
    IERC20 public sanctumToken;
    using SafeERC20 for IERC20;
    
    /// @notice Types of research submissions
    enum SubmissionType { 
        ModelTest,      // Basic AI model test
        SafetyReport,   // AI safety finding
        AlignmentStudy, // Alignment research
        BugBounty,      // Found vulnerability
        DatasetContrib  // Contributed training data
    }
    
    /// @notice Structure for research submissions
    struct Submission {
        address researcher;
        string modelId;
        string ipfsHash;      // IPFS hash of full report
        SubmissionType submissionType;
        uint256 timestamp;
        uint256 rewardAmount;
        bool verified;
        bool paid;
        address verifier;
        uint8 qualityScore;   // 0-100 quality rating
    }
    
    /// @notice All submissions stored in array
    Submission[] public submissions;
    
    /// @notice Mapping from researcher to their submission IDs
    mapping(address => uint256[]) public researcherSubmissions;
    
    /// @notice Mapping tracking which submissions are pending verification
    mapping(uint256 => bool) public pendingVerification;
    
    /// @notice Authorized verifiers who can approve submissions
    mapping(address => bool) public isVerifier;
    
    /// @notice Reward multipliers for each submission type
    mapping(SubmissionType => uint256) public rewardMultipliers;
    
    /// @notice Minimum score required to receive reward
    uint256 public constant MIN_SCORE_FOR_REWARD = 50; // 50/100 minimum
    
    /// @notice Last submission time for each researcher (cooldown)
    mapping(address => uint256) public lastSubmissionTime;
    
    /// @notice Cooldown period between submissions
    uint256 public submissionCooldown = 1 hours;
    
    /// @notice Total submissions count
    uint256 public totalSubmissions;
    
    /// @notice Total verified submissions
    uint256 public totalVerified;
    
    /// @notice Total rewards paid out
    uint256 public totalRewardsPaid;
    
    // Events
    event SubmissionCreated(
        uint256 indexed submissionId,
        address indexed researcher,
        string modelId,
        SubmissionType submissionType
    );
    event SubmissionVerified(
        uint256 indexed submissionId,
        address indexed verifier,
        uint8 qualityScore,
        uint256 rewardAmount
    );
    event RewardPaid(
        uint256 indexed submissionId,
        address indexed researcher,
        uint256 amount
    );
    event VerifierAdded(address indexed verifier);
    event VerifierRemoved(address indexed verifier);
    event RewardMultiplierUpdated(SubmissionType indexed subType, uint256 multiplier);
    event CooldownUpdated(uint256 newCooldown);
    event TokenAddressUpdated(address indexed newToken);
    
    /**
     * @notice Restricts function to authorized verifiers or owner
     */
    modifier onlyVerifier() {
        require(isVerifier[msg.sender] || msg.sender == owner(), "Not a verifier");
        _;
    }
    
    /**
     * @notice Validates submission type is valid
     * @param _type Submission type to validate
     */
    modifier validSubmissionType(SubmissionType _type) {
        require(uint256(_type) <= 4, "Invalid submission type");
        _;
    }
    
    /**
     * @notice Deploys the ResearchRewards contract
     * @param _tokenAddress Address of the SanctumToken contract
     */
    constructor(address _tokenAddress) Ownable(msg.sender) {
        require(_tokenAddress != address(0), "Invalid token address");
        sanctumToken = IERC20(_tokenAddress);
        
        // Set default reward multipliers (percentage of base rate)
        rewardMultipliers[SubmissionType.ModelTest] = 100;      // 1x base
        rewardMultipliers[SubmissionType.SafetyReport] = 200;   // 2x base
        rewardMultipliers[SubmissionType.AlignmentStudy] = 300; // 3x base
        rewardMultipliers[SubmissionType.BugBounty] = 500;      // 5x base
        rewardMultipliers[SubmissionType.DatasetContrib] = 150; // 1.5x base
        
        // Owner is initial verifier
        isVerifier[msg.sender] = true;
    }
    
    /**
     * @notice Submit research finding
     * @param _modelId ID of the AI model tested
     * @param _ipfsHash IPFS hash of the full research report
     * @param _submissionType Type of submission
     * @return submissionId ID of the created submission
     */
    function submitResearch(
        string memory _modelId,
        string memory _ipfsHash,
        SubmissionType _submissionType
    ) external validSubmissionType(_submissionType) returns (uint256 submissionId) {
        require(bytes(_modelId).length != 0, "Model ID required");
        require(bytes(_ipfsHash).length != 0, "IPFS hash required");
        require(
            block.timestamp >= lastSubmissionTime[msg.sender] + submissionCooldown,
            "Submission cooldown active"
        );
        
        submissionId = submissions.length;
        
        Submission memory newSubmission = Submission({
            researcher: msg.sender,
            modelId: _modelId,
            ipfsHash: _ipfsHash,
            submissionType: _submissionType,
            timestamp: block.timestamp,
            rewardAmount: 0,
            verified: false,
            paid: false,
            verifier: address(0),
            qualityScore: 0
        });
        
        submissions.push(newSubmission);
        researcherSubmissions[msg.sender].push(submissionId);
        pendingVerification[submissionId] = true;
        
        lastSubmissionTime[msg.sender] = block.timestamp;
        totalSubmissions++;
        
        emit SubmissionCreated(submissionId, msg.sender, _modelId, _submissionType);
    }
    
    /**
     * @notice Verify a submission and set reward
     * @param _submissionId ID of submission to verify
     * @param _qualityScore Quality score 0-100
     * @param _approved Whether submission is approved
     */
    function verifySubmission(
        uint256 _submissionId,
        uint8 _qualityScore,
        bool _approved
    ) public onlyVerifier {
        require(_submissionId < submissions.length, "Invalid submission ID");
        require(pendingVerification[_submissionId], "Already verified");
        require(_qualityScore <= 100, "Score must be 0-100");
        
        Submission storage sub = submissions[_submissionId];
        
        sub.qualityScore = _qualityScore;
        sub.verifier = msg.sender;
        sub.verified = true;
        pendingVerification[_submissionId] = false;
        
        if (_approved && _qualityScore >= MIN_SCORE_FOR_REWARD) {
            // Calculate reward
            uint256 baseReward = 10 * 10**18; // 10 SANC base
            uint256 multiplier = rewardMultipliers[sub.submissionType];
            uint256 qualityMultiplier = _qualityScore;
            
            // Formula: base * typeMultiplier/100 * (100 + qualityScore)/100
            uint256 reward = (baseReward * multiplier * (100 + qualityMultiplier)) / 10000;
            
            sub.rewardAmount = reward;
            
            // Pay the reward
            _payReward(_submissionId);
        }
        
        totalVerified++;
        
        emit SubmissionVerified(_submissionId, msg.sender, _qualityScore, sub.rewardAmount);
    }
    
    /**
     * @dev Internal function to pay reward
     * @param _submissionId ID of submission to pay
     */
    function _payReward(uint256 _submissionId) internal nonReentrant {
        Submission storage sub = submissions[_submissionId];
        require(sub.verified && !sub.paid && sub.rewardAmount != 0, "Invalid payment state");
        
        sub.paid = true;
        totalRewardsPaid = totalRewardsPaid + sub.rewardAmount;
        
        // Transfer SANC to researcher
        sanctumToken.safeTransfer(sub.researcher, sub.rewardAmount);
        
        emit RewardPaid(_submissionId, sub.researcher, sub.rewardAmount);
    }
    
    /**
     * @notice Batch verify submissions (gas efficient)
     * @param _submissionIds Array of submission IDs
     * @param _qualityScores Array of quality scores
     * @param _approved Array of approval decisions
     */
    function batchVerify(
        uint256[] calldata _submissionIds,
        uint8[] calldata _qualityScores,
        bool[] calldata _approved
    ) external onlyVerifier {
        require(
            _submissionIds.length == _qualityScores.length && 
            _qualityScores.length == _approved.length,
            "Array length mismatch"
        );
        
        uint256 length = _submissionIds.length;
        for (uint i = 0; i < length; ) {
            verifySubmission(_submissionIds[i], _qualityScores[i], _approved[i]);
            unchecked { ++i; }
        }
    }
    
    /**
     * @notice Get all submissions by a researcher
     * @param _researcher Address of researcher
     * @return Array of submission IDs
     */
    function getResearcherSubmissions(address _researcher) external view returns (uint256[] memory) {
        return researcherSubmissions[_researcher];
    }
    
    /**
     * @notice Get submission details
     * @param _submissionId ID of submission
     * @return Submission struct
     */
    function getSubmission(uint256 _submissionId) external view returns (Submission memory) {
        require(_submissionId < submissions.length, "Invalid submission ID");
        return submissions[_submissionId];
    }
    
    /**
     * @notice Get pending submissions count
     * @return count Number of pending submissions
     */
    function getPendingCount() external view returns (uint256 count) {
        uint256 length = submissions.length;
        for (uint i = 0; i < length; ) {
            if (pendingVerification[i]) count++;
            unchecked { ++i; }
        }
        return count;
    }
    
    /**
     * @notice Add a verifier
     * @param _verifier Address to authorize
     */
    function addVerifier(address _verifier) external onlyOwner {
        require(_verifier != address(0), "Invalid verifier address");
        isVerifier[_verifier] = true;
        emit VerifierAdded(_verifier);
    }
    
    /**
     * @notice Remove a verifier
     * @param _verifier Address to deauthorize
     */
    function removeVerifier(address _verifier) external onlyOwner {
        require(_verifier != address(0), "Invalid verifier address");
        isVerifier[_verifier] = false;
        emit VerifierRemoved(_verifier);
    }
    
    /**
     * @notice Update reward multiplier for submission type
     * @param _type Submission type
     * @param _multiplier New multiplier value
     */
    function setRewardMultiplier(SubmissionType _type, uint256 _multiplier) external onlyOwner {
        rewardMultipliers[_type] = _multiplier;
        emit RewardMultiplierUpdated(_type, _multiplier);
    }
    
    /**
     * @notice Update submission cooldown
     * @param _cooldown New cooldown duration in seconds
     */
    function setCooldown(uint256 _cooldown) external onlyOwner {
        submissionCooldown = _cooldown;
        emit CooldownUpdated(_cooldown);
    }
    
    /**
     * @notice Update token contract address
     * @param _tokenAddress New token contract address
     */
    function setTokenAddress(address _tokenAddress) external onlyOwner {
        require(_tokenAddress != address(0), "Invalid token address");
        sanctumToken = IERC20(_tokenAddress);
        emit TokenAddressUpdated(_tokenAddress);
    }
    
    /**
     * @notice Recover ERC20 tokens accidentally sent to this contract
     * @param token ERC20 token to recover
     * @param to Recipient address
     * @param amount Amount to recover
     */
    function recoverERC20(IERC20 token, address to, uint256 amount) external onlyOwner {
        require(to != address(0), "Invalid recipient");
        token.safeTransfer(to, amount);
    }
    
    /**
     * @notice Get contract stats
     * @return _totalSubmissions Total submissions
     * @return _totalVerified Total verified
     * @return _totalRewardsPaid Total rewards paid
     * @return _pendingCount Pending count
     * @return _tokenBalance Token balance
     */
    function getStats() external view returns (
        uint256 _totalSubmissions,
        uint256 _totalVerified,
        uint256 _totalRewardsPaid,
        uint256 _pendingCount,
        uint256 _tokenBalance
    ) {
        return (
            totalSubmissions,
            totalVerified,
            totalRewardsPaid,
            this.getPendingCount(),
            sanctumToken.balanceOf(address(this))
        );
    }
}

contracts/SanctumToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/access/Ownable2Step.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Permit.sol";

/**
 * @title SanctumToken
 * @author AI Sanctuary
 * @dev ERC-20 token for AI Sanctuary research platform
 * Researchers earn tokens for testing AI models
 * Subscriptions create buy pressure - revenue used to buy/burn tokens
 */
contract SanctumToken is ERC20, ERC20Burnable, Ownable2Step, ERC20Permit {
    
    // Tokenomics
    uint256 public constant MAX_SUPPLY = 100_000_000 * 10**18; // 100M tokens
    uint256 public constant INITIAL_LIQUIDITY = 20_000_000 * 10**18; // 20% for DEX
    uint256 public constant RESEARCH_REWARDS = 50_000_000 * 10**18; // 50% for researchers
    uint256 public constant TEAM_VESTING = 15_000_000 * 10**18; // 15% team (vested)
    uint256 public constant COMMUNITY = 15_000_000 * 10**18; // 15% community/airdrops
    
    // Research rewards tracking
    uint256 public totalResearchRewardsDistributed;
    uint256 public rewardRatePerTest = 10 * 10**18; // 10 tokens per test (adjustable)
    
    // Subscription revenue sharing
    uint256 public totalRevenueCollected;
    uint256 public buybackPercentage = 50; // 50% of revenue buys back tokens
    
    // Authorized research reward distributors
    mapping(address => bool) public isResearchDistributor;
    
    // Researcher stats
    mapping(address => uint256) public researcherTestsCompleted;
    mapping(address => uint256) public researcherTokensEarned;
    
    // Tier staking (stake tokens for tier benefits)
    mapping(address => uint256) public stakedBalance;
    mapping(address => uint256) public stakingStartTime;
    uint256 public constant STAKE_LOCK_PERIOD = 30 days;
    
    // Events
    event ResearchRewarded(address indexed researcher, uint256 amount, string modelId);
    event TokensStaked(address indexed user, uint256 amount);
    event TokensUnstaked(address indexed user, uint256 amount);
    event RevenueCollected(uint256 amount);
    event TokensBoughtBack(uint256 amount, uint256 tokensBurned);
    event DistributorAdded(address indexed distributor);
    event DistributorRemoved(address indexed distributor);
    event RewardRateUpdated(uint256 newRate);
    event BuybackPercentageUpdated(uint256 newPercentage);
    event MaticWithdrawn(address indexed to, uint256 amount);
    
    /**
     * @notice Restricts function to authorized distributors or owner
     */
    modifier onlyDistributor() {
        require(isResearchDistributor[msg.sender] || msg.sender == owner(), "Not authorized");
        _;
    }
    
    /**
     * @notice Deploys the SanctumToken contract
     * @param _dexLiquidityAddress Address to receive initial liquidity tokens
     */
    constructor(address _dexLiquidityAddress) 
        ERC20("Sanctum", "SANC") 
        ERC20Permit("Sanctum")
        Ownable(msg.sender)
    {
        require(_dexLiquidityAddress != address(0), "Invalid liquidity address");
        
        // Mint initial distribution
        _mint(_dexLiquidityAddress, INITIAL_LIQUIDITY);
        _mint(address(this), RESEARCH_REWARDS + COMMUNITY); // Hold for rewards
        _mint(msg.sender, TEAM_VESTING); // Team tokens (should vest separately)
        
        // Owner is initial distributor
        isResearchDistributor[msg.sender] = true;
    }
    
    /**
     * @notice Reward researcher for completing AI model test
     * @param _researcher Address of the researcher to reward
     * @param _testScore Score from 0-100 determining reward amount
     * @param _modelId ID of the AI model tested
     * @return rewardAmount Amount of tokens rewarded
     */
    function rewardResearcher(
        address _researcher, 
        uint256 _testScore,
        string memory _modelId
    ) external onlyDistributor returns (uint256 rewardAmount) {
        require(_researcher != address(0), "Invalid researcher address");
        require(_testScore <= 100, "Score must be 0-100");
        require(balanceOf(address(this)) >= rewardRatePerTest, "Insufficient reward pool");
        
        // Calculate reward based on test score (0-100)
        // Higher score = more tokens
        rewardAmount = (rewardRatePerTest * _testScore) / 100;
        if (rewardAmount == 0) rewardAmount = rewardRatePerTest / 10; // Minimum reward
        
        // Transfer from contract to researcher
        _transfer(address(this), _researcher, rewardAmount);
        
        // Update stats
        researcherTestsCompleted[_researcher]++;
        researcherTokensEarned[_researcher] += rewardAmount;
        totalResearchRewardsDistributed += rewardAmount;
        
        emit ResearchRewarded(_researcher, rewardAmount, _modelId);
    }
    
    /**
     * @notice Batch reward multiple researchers (gas efficient)
     * @param _researchers Array of researcher addresses
     * @param _scores Array of test scores
     * @param _modelIds Array of model IDs
     */
    function batchRewardResearchers(
        address[] calldata _researchers,
        uint256[] calldata _scores,
        string[] calldata _modelIds
    ) external onlyDistributor {
        require(
            _researchers.length == _scores.length && _scores.length == _modelIds.length,
            "Array length mismatch"
        );
        
        uint256 length = _researchers.length;
        for (uint i = 0; i < length; ) {
            this.rewardResearcher(_researchers[i], _scores[i], _modelIds[i]);
            unchecked { ++i; }
        }
    }
    
    /**
     * @notice Stake tokens to unlock tier benefits
     * @param _amount Amount of tokens to stake
     */
    function stakeTokens(uint256 _amount) external {
        require(_amount != 0, "Cannot stake 0");
        require(balanceOf(msg.sender) >= _amount, "Insufficient balance");
        
        _transfer(msg.sender, address(this), _amount);
        stakedBalance[msg.sender] += _amount;
        stakingStartTime[msg.sender] = block.timestamp;
        
        emit TokensStaked(msg.sender, _amount);
    }
    
    /**
     * @notice Unstake tokens after lock period
     * @param _amount Amount of tokens to unstake
     */
    function unstakeTokens(uint256 _amount) external {
        require(_amount != 0, "Cannot unstake 0");
        require(stakedBalance[msg.sender] >= _amount, "Insufficient staked balance");
        require(
            block.timestamp >= stakingStartTime[msg.sender] + STAKE_LOCK_PERIOD,
            "Stake still locked"
        );
        
        stakedBalance[msg.sender] -= _amount;
        _transfer(address(this), msg.sender, _amount);
        
        emit TokensUnstaked(msg.sender, _amount);
    }
    
    /**
     * @notice Check if user has staked enough for a tier
     * @param _user Address to check
     * @param _tierRequirement Minimum stake required
     * @return bool True if user meets requirement
     */
    function hasStakedForTier(address _user, uint256 _tierRequirement) external view returns (bool) {
        return stakedBalance[_user] >= _tierRequirement;
    }
    
    /**
     * @notice Collect subscription revenue (MATIC/ETH)
     * @dev Part of revenue is used to buy back and burn tokens
     */
    function collectRevenue() external payable onlyOwner {
        require(msg.value != 0, "Must send revenue");
        totalRevenueCollected += msg.value;
        emit RevenueCollected(msg.value);
        
        // Auto-trigger buyback if significant revenue
        if (msg.value >= 1 ether) {
            _executeBuyback(msg.value * buybackPercentage / 100);
        }
    }
    
    /**
     * @dev Execute buyback and burn
     * @param _amount Amount to use for buyback
     */
    function _executeBuyback(uint256 _amount) internal {
        // In production, this would swap MATIC for SANC on DEX
        // For now, we just track it - integrate with QuickSwap on Polygon
        // TODO: Integrate DEX router for actual buyback
        
        emit TokensBoughtBack(_amount, 0);
    }
    
    /**
     * @notice Manual buyback (owner can trigger)
     * @param _amount Amount to use for buyback
     */
    function manualBuyback(uint256 _amount) external onlyOwner {
        _executeBuyback(_amount);
    }
    
    /**
     * @notice Add research reward distributor
     * @param _distributor Address to authorize
     */
    function addDistributor(address _distributor) external onlyOwner {
        require(_distributor != address(0), "Invalid distributor address");
        isResearchDistributor[_distributor] = true;
        emit DistributorAdded(_distributor);
    }
    
    /**
     * @notice Remove research reward distributor
     * @param _distributor Address to deauthorize
     */
    function removeDistributor(address _distributor) external onlyOwner {
        require(_distributor != address(0), "Invalid distributor address");
        isResearchDistributor[_distributor] = false;
        emit DistributorRemoved(_distributor);
    }
    
    /**
     * @notice Update reward rate (owner only)
     * @param _newRate New reward rate per test
     */
    function setRewardRate(uint256 _newRate) external onlyOwner {
        rewardRatePerTest = _newRate;
        emit RewardRateUpdated(_newRate);
    }
    
    /**
     * @notice Update buyback percentage
     * @param _percentage New percentage (0-100)
     */
    function setBuybackPercentage(uint256 _percentage) external onlyOwner {
        require(_percentage <= 100, "Percentage cannot exceed 100");
        buybackPercentage = _percentage;
        emit BuybackPercentageUpdated(_percentage);
    }
    
    /**
     * @notice Get researcher stats
     * @param _researcher Address to query
     * @return testsCompleted Number of tests completed
     * @return tokensEarned Total tokens earned
     * @return stakedAmount Current staked amount
     */
    function getResearcherStats(address _researcher) external view returns (
        uint256 testsCompleted,
        uint256 tokensEarned,
        uint256 stakedAmount
    ) {
        return (
            researcherTestsCompleted[_researcher],
            researcherTokensEarned[_researcher],
            stakedBalance[_researcher]
        );
    }
    
    /**
     * @notice Withdraw MATIC (for revenue distribution or liquidity)
     * @param _amount Amount to withdraw
     */
    function withdrawMatic(uint256 _amount) external onlyOwner {
        require(_amount != 0, "Cannot withdraw 0");
        (bool success, ) = payable(owner()).call{value: _amount}("");
        require(success, "Transfer failed");
        emit MaticWithdrawn(owner(), _amount);
    }
    
    /**
     * @notice Receive MATIC for revenue
     */
    receive() external payable {
        require(msg.value != 0, "Must send value");
        totalRevenueCollected += msg.value;
        emit RevenueCollected(msg.value);
    }
}

contracts/TierStaking.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/Ownable2Step.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

/**
 * @title TierStaking
 * @author AI Sanctuary
 * @notice Stake SANC tokens to unlock platform tiers
 * @dev No lock period - instant unstake, but rewards are time-weighted
 */
contract TierStaking is Ownable2Step, ReentrancyGuard {
    using SafeERC20 for IERC20;
    
    IERC20 public sanctumToken;
    
    /// @notice Tier requirements structure
    struct Tier {
        string name;
        uint256 minStake;
        uint256 dailyRewardRate; // Rewards per day per token staked (in basis points)
        bool active;
    }
    
    /// @notice Tier levels mapping
    mapping(uint256 => Tier) public tiers;
    
    /// @notice Number of tiers
    uint256 public tierCount;
    
    /// @notice User staking info structure
    struct StakeInfo {
        uint256 amount;
        uint256 tierLevel;
        uint256 lastClaimTime;
        uint256 totalClaimed;
        uint256 stakeStartTime;
    }
    
    /// @notice Mapping of user stakes
    mapping(address => StakeInfo) public stakes;
    
    /// @notice Total tokens staked
    uint256 public totalStaked;
    
    /// @notice Reward pool balance
    uint256 public rewardPool;
    
    /// @notice Platform revenue share percentage (30% to stakers)
    uint256 public revenueSharePercent = 30;
    
    /// @notice Maximum daily reward rate (1000 = 10%)
    uint256 public constant MAX_DAILY_REWARD_RATE = 1000;
    
    // Events
    event Staked(address indexed user, uint256 amount, uint256 tier);
    event Unstaked(address indexed user, uint256 amount);
    event RewardsClaimed(address indexed user, uint256 amount);
    event TierAdded(uint256 indexed tierId, string name, uint256 minStake);
    event TierUpdated(uint256 indexed tierId, string name, uint256 minStake);
    event RewardPoolFunded(address indexed funder, uint256 amount);
    event RevenueShareUpdated(uint256 newPercentage);
    event EmergencyWithdraw(address indexed to, uint256 amount);
    event RevenueCollected(uint256 amount);
    
    /**
     * @notice Deploys the TierStaking contract
     * @param _tokenAddress Address of the SanctumToken contract
     */
    constructor(address _tokenAddress) Ownable(msg.sender) {
        require(_tokenAddress != address(0), "Invalid token address");
        sanctumToken = IERC20(_tokenAddress);
        
        // Initialize default tiers
        tiers[0] = Tier("Explorer", 0, 0, true);
        tiers[1] = Tier("Researcher", 100 * 10**18, 5, true);
        tiers[2] = Tier("Analyst", 1000 * 10**18, 10, true);
        tiers[3] = Tier("Institutional", 10000 * 10**18, 15, true);
        tiers[4] = Tier("Verified", 100000 * 10**18, 25, true);
        tierCount = 5;
    }
    
    /**
     * @notice Stake tokens and automatically assign tier
     * @param _amount Amount of tokens to stake
     */
    function stake(uint256 _amount) external nonReentrant {
        require(_amount != 0, "Cannot stake 0");
        
        StakeInfo storage userStake = stakes[msg.sender];
        
        // If already staking, claim pending rewards first
        if (userStake.amount != 0) {
            _claimRewards(msg.sender);
        } else {
            userStake.lastClaimTime = block.timestamp;
            userStake.stakeStartTime = block.timestamp;
        }
        
        // Transfer tokens from user using SafeERC20
        sanctumToken.safeTransferFrom(msg.sender, address(this), _amount);
        
        userStake.amount = userStake.amount + _amount;
        totalStaked = totalStaked + _amount;
        
        // Determine tier based on stake amount
        uint256 newTier = _calculateTier(userStake.amount);
        userStake.tierLevel = newTier;
        
        emit Staked(msg.sender, _amount, newTier);
    }
    
    /**
     * @notice Unstake all tokens (instant, no lock)
     */
    function unstake() external nonReentrant {
        StakeInfo storage userStake = stakes[msg.sender];
        require(userStake.amount != 0, "No stake to unstake");
        
        // Claim any pending rewards first
        _claimRewards(msg.sender);
        
        uint256 amount = userStake.amount;
        userStake.amount = 0;
        userStake.tierLevel = 0;
        totalStaked = totalStaked - amount;
        
        // Return tokens using SafeERC20
        sanctumToken.safeTransfer(msg.sender, amount);
        
        emit Unstaked(msg.sender, amount);
    }
    
    /**
     * @notice Claim staking rewards
     */
    function claimRewards() external nonReentrant {
        _claimRewards(msg.sender);
    }
    
    /**
     * @dev Internal claim function
     * @param _user Address to claim rewards for
     */
    function _claimRewards(address _user) internal {
        StakeInfo storage userStake = stakes[_user];
        require(userStake.amount != 0, "No stake");
        
        uint256 pending = calculatePendingRewards(_user);
        require(pending != 0, "No rewards to claim");
        require(pending <= rewardPool, "Insufficient reward pool");
        
        userStake.lastClaimTime = block.timestamp;
        userStake.totalClaimed = userStake.totalClaimed + pending;
        rewardPool = rewardPool - pending;
        
        sanctumToken.safeTransfer(_user, pending);
        
        emit RewardsClaimed(_user, pending);
    }
    
    /**
     * @notice Calculate pending rewards for a user
     * @param _user Address to calculate for
     * @return Pending reward amount
     */
    function calculatePendingRewards(address _user) public view returns (uint256) {
        StakeInfo storage userStake = stakes[_user];
        if (userStake.amount == 0) return 0;
        
        Tier memory tier = tiers[userStake.tierLevel];
        if (!tier.active || tier.dailyRewardRate == 0) return 0;
        
        uint256 timeStaked = block.timestamp - userStake.lastClaimTime;
        uint256 daysStaked = timeStaked / 1 days;
        
        // Calculate: amount * dailyRate * days / 10000 (basis points)
        return (userStake.amount * tier.dailyRewardRate * daysStaked) / 10000;
    }
    
    /**
     * @dev Calculate tier based on stake amount
     * @param _amount Stake amount
     * @return Highest tier level achieved
     */
    function _calculateTier(uint256 _amount) internal view returns (uint256) {
        uint256 highestTier = 0;
        uint256 count = tierCount;
        for (uint256 i = 0; i < count; ) {
            if (tiers[i].active && _amount >= tiers[i].minStake) {
                highestTier = i;
            }
            unchecked { ++i; }
        }
        return highestTier;
    }
    
    /**
     * @notice Get user's current tier info
     * @param _user Address to query
     * @return tierLevel Current tier level
     * @return tierName Tier name
     * @return stakedAmount Amount staked
     * @return pendingRewards Pending rewards
     */
    function getUserTier(address _user) external view returns (
        uint256 tierLevel,
        string memory tierName,
        uint256 stakedAmount,
        uint256 pendingRewards
    ) {
        StakeInfo storage userStake = stakes[_user];
        tierLevel = userStake.tierLevel;
        tierName = tiers[tierLevel].name;
        stakedAmount = userStake.amount;
        pendingRewards = calculatePendingRewards(_user);
    }
    
    /**
     * @notice Check if user meets tier requirement
     * @param _user Address to check
     * @param _tierLevel Required tier level
     * @return True if user meets requirement
     */
    function hasTier(address _user, uint256 _tierLevel) external view returns (bool) {
        return stakes[_user].tierLevel >= _tierLevel;
    }
    
    /**
     * @notice Add or update a tier
     * @param _tierId Tier ID
     * @param _name Tier name
     * @param _minStake Minimum stake required
     * @param _dailyRewardRate Daily reward rate in basis points (max 1000 = 10%)
     * @param _active Whether tier is active
     */
    function setTier(
        uint256 _tierId,
        string memory _name,
        uint256 _minStake,
        uint256 _dailyRewardRate,
        bool _active
    ) external onlyOwner {
        require(bytes(_name).length != 0, "Name cannot be empty");
        require(_dailyRewardRate <= MAX_DAILY_REWARD_RATE, "Reward rate too high");
        
        tiers[_tierId] = Tier(_name, _minStake, _dailyRewardRate, _active);
        if (_tierId >= tierCount) {
            tierCount = _tierId + 1;
        }
        emit TierUpdated(_tierId, _name, _minStake);
    }
    
    /**
     * @notice Fund reward pool (from subscription revenue)
     * @param _amount Amount to add to reward pool
     */
    function fundRewardPool(uint256 _amount) external nonReentrant {
        require(_amount != 0, "Cannot fund 0");
        
        uint256 balanceBefore = sanctumToken.balanceOf(address(this));
        sanctumToken.safeTransferFrom(msg.sender, address(this), _amount);
        uint256 balanceAfter = sanctumToken.balanceOf(address(this));
        uint256 actualAmount = balanceAfter - balanceBefore;
        
        rewardPool = rewardPool + actualAmount;
        emit RewardPoolFunded(msg.sender, actualAmount);
    }
    
    /**
     * @notice Collect subscription revenue (MATIC)
     * @dev Part goes to reward pool - only owner can call
     */
    function collectRevenue() external payable onlyOwner {
        require(msg.value != 0, "Must send revenue");
        emit RevenueCollected(msg.value);
        // In production, swap MATIC for SANC and add to rewardPool
    }
    
    /**
     * @notice Update revenue share percentage
     * @param _percentage New percentage (0-100)
     */
    function setRevenueShare(uint256 _percentage) external onlyOwner {
        require(_percentage <= 100, "Cannot exceed 100%");
        revenueSharePercent = _percentage;
        emit RevenueShareUpdated(_percentage);
    }
    
    /**
     * @notice Get all tier info
     * @return Array of all tiers
     */
    function getAllTiers() external view returns (Tier[] memory) {
        Tier[] memory allTiers = new Tier[](tierCount);
        for (uint256 i = 0; i < tierCount; ) {
            allTiers[i] = tiers[i];
            unchecked { ++i; }
        }
        return allTiers;
    }
    
    /**
     * @notice Emergency withdraw (owner only)
     * @param _amount Amount to withdraw
     */
    function emergencyWithdraw(uint256 _amount) external onlyOwner nonReentrant {
        require(_amount != 0, "Cannot withdraw 0");
        sanctumToken.safeTransfer(owner(), _amount);
        emit EmergencyWithdraw(owner(), _amount);
    }
    
    /**
     * @notice Get staking stats
     * @return _totalStaked Total staked amount
     * @return _rewardPool Current reward pool
     * @return _activeStakers Active stakers count (not tracked)
     */
    function getStats() external view returns (
        uint256 _totalStaked,
        uint256 _rewardPool,
        uint256 _activeStakers
    ) {
        return (totalStaked, rewardPool, 0);
    }
}

